using System.Collections.Generic;
using BalloonParty.Balloon.Model;
using BalloonParty.Shared.Messages;
using BalloonParty.Slots;
using DG.Tweening;
using MessagePipe;
using UnityEngine;
using VContainer;
using VContainer.Unity;

namespace BalloonParty.Balloon.Controller
{
    public class BalloonBalancer : IStartable
    {
        private readonly IGameConfiguration _config;
        private readonly SlotGrid _grid;
        private readonly ISubscriber<BalanceBalloonsMessage> _subscriber;

        [Inject]
        public BalloonBalancer(SlotGrid grid, IGameConfiguration config, ISubscriber<BalanceBalloonsMessage> subscriber)
        {
            _grid = grid;
            _config = config;
            _subscriber = subscriber;
        }

        public void Start()
        {
            _subscriber.Subscribe(_ => Balance());
        }

        private void Balance()
        {
            var paths = new Dictionary<BalloonModel, List<Vector3>>();
            var origins = new Dictionary<BalloonModel, Vector3>();
            var hasUnbalanced = true;

            while (hasUnbalanced)
            {
                hasUnbalanced = false;

                for (var col = 0; col < _grid.Columns; col++)
                for (var row = _grid.Rows - 1; row >= 0; row--)
                {
                    if (_grid.IsEmpty(col, row)) continue;
                    if (!_grid.IsUnbalanced(col, row)) continue;

                    var nextSlot = _grid.OptimalNextEmptySlot(col, row);
                    if (!nextSlot.HasValue) continue;

                    var balloon = _grid.At(new Vector2Int(col, row));

                    hasUnbalanced = true;

                    // Record the origin position only the first time this balloon is picked up,
                    // so the DOPath starts from the correct grid position — not a tween-displaced one.
                    if (!origins.ContainsKey(balloon))
                        origins[balloon] = _grid.IndexToWorldPosition(new Vector2Int(col, row));

                    _grid.Remove(new Vector2Int(col, row));
                    _grid.Place(balloon, nextSlot.Value);
                    balloon.IsStable.Value = false;

                    var targetPosition = _grid.IndexToWorldPosition(nextSlot.Value);
                    if (paths.TryGetValue(balloon, out var path))
                        path.Add(targetPosition);
                    else
                        paths[balloon] = new List<Vector3> { targetPosition };
                }
            }

            AnimatePaths(paths, origins);
        }

        private void AnimatePaths(Dictionary<BalloonModel, List<Vector3>> paths,
            Dictionary<BalloonModel, Vector3> origins)
        {
            foreach (var (balloon, path) in paths)
            {
                var view = balloon.View;
                if (view == null) continue;

                view.transform.DOKill();
                view.transform.localScale = Vector3.one;

                // Snap to the grid position before balance moved it,
                // so the path doesn't start from a nudge/tween-displaced position.
                if (origins.TryGetValue(balloon, out var origin))
                    view.transform.position = origin;

                view.transform
                    .DOPath(path.ToArray(), _config.TimeForBalloonsBalance, PathType.Linear)
                    .SetId(view.GetInstanceID())
                    .OnComplete(() => balloon.IsStable.Value = true);
            }
        }
    }
}

using System.Collections.Generic;
using BalloonParty.Balloon.Model;
using BalloonParty.Shared.Messages;
using BalloonParty.Slots;
using DG.Tweening;
using MessagePipe;
using UnityEngine;
using VContainer;
using VContainer.Unity;

namespace BalloonParty.Balloon.Controller
{
    public class BalloonBalancer : IStartable
    {
        private readonly IGameConfiguration _config;
        private readonly SlotGrid _grid;
        private readonly ISubscriber<BalanceBalloonsMessage> _subscriber;

        [Inject]
        public BalloonBalancer(SlotGrid grid, IGameConfiguration config, ISubscriber<BalanceBalloonsMessage> subscriber)
        {
            _grid = grid;
            _config = config;
            _subscriber = subscriber;
        }

        public void Start()
        {
            _subscriber.Subscribe(_ => Balance());
        }

        private void Balance()
        {
            // Pass 1: balance only stable (surviving) balloons — they get priority to fill gaps.
            var stablePaths = BalancePass(stableOnly: true);

            // Pass 2: balance unstable (newly spawned) balloons into remaining gaps.
            var unstablePaths = BalancePass(stableOnly: false);

            AnimateStablePaths(stablePaths);
            AnimateSpawnedPaths(unstablePaths);
        }

        private Dictionary<BalloonModel, (Vector3 origin, List<Vector3> waypoints)> BalancePass(bool stableOnly)
        {
            var paths = new Dictionary<BalloonModel, (Vector3 origin, List<Vector3> waypoints)>();
            var hasUnbalanced = true;

            while (hasUnbalanced)
            {
                hasUnbalanced = false;

                for (var col = 0; col < _grid.Columns; col++)
                for (var row = _grid.Rows - 1; row >= 0; row--)
                {
                    if (_grid.IsEmpty(col, row)) continue;
                    if (!_grid.IsUnbalanced(col, row)) continue;

                    var nextSlot = _grid.OptimalNextEmptySlot(col, row);
                    if (!nextSlot.HasValue) continue;

                    var balloon = _grid.At(new Vector2Int(col, row));
                    if (stableOnly && !balloon.IsStable.Value) continue;
                    if (!stableOnly && balloon.IsStable.Value) continue;

                    hasUnbalanced = true;

                    var originPos = _grid.IndexToWorldPosition(new Vector2Int(col, row));

                    _grid.Remove(new Vector2Int(col, row));
                    _grid.Place(balloon, nextSlot.Value);
                    balloon.IsStable.Value = false;

                    var targetPosition = _grid.IndexToWorldPosition(nextSlot.Value);
                    if (paths.TryGetValue(balloon, out var entry))
                        entry.waypoints.Add(targetPosition);
                    else
                        paths[balloon] = (originPos, new List<Vector3> { targetPosition });
                }
            }

            return paths;
        }

        private void AnimateStablePaths(
            Dictionary<BalloonModel, (Vector3 origin, List<Vector3> waypoints)> paths)
        {
            foreach (var (balloon, (origin, waypoints)) in paths)
            {
                var view = balloon.View;
                if (view == null) continue;

                // Surviving balloons: kill any nudge/balance tweens,
                // snap to grid origin so the path starts from the correct position.
                view.transform.DOKill();
                view.transform.localScale = Vector3.one;
                view.transform.position = origin;

                view.transform
                    .DOPath(waypoints.ToArray(), _config.TimeForBalloonsBalance, PathType.Linear)
                    .SetId(view.GetInstanceID())
                    .OnComplete(() => balloon.IsStable.Value = true);
            }
        }

        private void AnimateSpawnedPaths(
            Dictionary<BalloonModel, (Vector3 origin, List<Vector3> waypoints)> paths)
        {
            foreach (var (balloon, (_, waypoints)) in paths)
            {
                var view = balloon.View;
                if (view == null) continue;

                // Newly spawned balloons: kill the spawn move tween (redirecting to new target)
                // but keep the scale tween so they scale up smoothly.
                DOTween.Kill(view.GetInstanceID());

                var finalTarget = waypoints[^1];
                view.transform
                    .DOMove(finalTarget, _config.TimeForBalloonsBalance)
                    .SetId(view.GetInstanceID())
                    .OnComplete(() => balloon.IsStable.Value = true);
            }
        }
    }
}

using BalloonParty.Balloon.View;
using UniRx;
using UnityEngine;

namespace BalloonParty.Balloon.Model
{
    public class BalloonModel
    {
        public ReactiveProperty<string> Color { get; } = new();
        public ReactiveProperty<Vector2Int> SlotIndex { get; } = new();
        public ReactiveProperty<bool> IsStable { get; } = new(true);

        // Weight influences which empty slot a balloon moves to during balancing.
        public int SlotWeight { get; set; }

        // Set by BalloonController when the view is bound, so other systems can reach the transform.
        public BalloonView View { get; set; }
    }
}

using BalloonParty.Balloon.View;
using UniRx;
using UnityEngine;

namespace BalloonParty.Balloon.Model
{
    public class BalloonModel
    {
        public ReactiveProperty<string> Color { get; } = new();
        public ReactiveProperty<Vector2Int> SlotIndex { get; } = new();
        public ReactiveProperty<bool> IsStable { get; } = new(true);

        // Weight influences which empty slot a balloon moves to during balancing.
        public int SlotWeight { get; set; }

        // True until the balloon's spawn animation completes and it becomes stable for the first time.
        public bool IsNewlySpawned { get; set; } = true;

        // Set by BalloonController when the view is bound, so other systems can reach the transform.
        public BalloonView View { get; set; }
    }
}

using System;
using BalloonParty.Balloon.Model;
using BalloonParty.Shared;
using DG.Tweening;
using UniRx;
using UnityEngine;
using VContainer;

namespace BalloonParty.Balloon.View
{
    public class BalloonView : MonoBehaviour, IPoolable
    {
        [Header("References")] [SerializeField]
        private SpriteRenderer _renderer;

        [SerializeField] private SpriteRenderer _shadowRenderer;
        [SerializeField] private Animator _animator;
        [SerializeField] private Renderer[] _spriteLayerRenderers;
        [SerializeField] private ParticleSystem _popVfxPrefab;

        [Header("Shadow")] [SerializeField] [Range(0f, 1f)]
        private float _shadowAlpha;

        [SerializeField] [Range(0f, 5f)] private float _shadowIntensity;

        [Header("Sorting")] [SerializeField] private int _baseSortingLayer;

        [Inject] private IGameConfiguration _config;
        [Inject] private PoolManager _poolManager;

        private readonly CompositeDisposable _bindDisposables = new();

        public BalloonModel Model { get; private set; }
        public BalloonTweenTracker TweenTracker { get; private set; }

        private void Awake()
        {
            TweenTracker = GetComponent<BalloonTweenTracker>();
        }

        public void RegisterDisposeOnDespawn(IDisposable disposable)
        {
            _bindDisposables.Add(disposable);
        }

        public void Bind(BalloonModel model)
        {
            _bindDisposables.Clear();
            Model = model;

            model.Color
                .Subscribe(ApplyColor)
                .AddTo(_bindDisposables);

            model.SlotIndex
                .Subscribe(ApplySortingOrder)
                .AddTo(_bindDisposables);

            model.IsStable
                .Subscribe(stable => _animator.SetBool("IsStable", stable))
                .AddTo(_bindDisposables);
        }

        public void PlayPopEffect(Color color)
        {
            _poolManager.GetOrRegister(_popVfxPrefab.name, () => new VfxPoolChannel(_popVfxPrefab)).Play(transform.position, color);
        }

        public void OnSpawned()
        {
            transform.localScale = Vector3.one;
            transform.position = Vector3.one * -1000f;
        }

        public void OnDespawned()
        {
            TweenTracker.Kill();
            transform.DOKill();
            _bindDisposables.Clear();
            Model = null;
        }

        private void ApplyColor(string colorName)
        {
            var color = _config.BalloonColor(colorName);

            if (_renderer != null)
                _renderer.color = color;

            if (_shadowRenderer != null)
                _shadowRenderer.color = new Color(
                    color.r * _shadowIntensity,
                    color.g * _shadowIntensity,
                    color.b * _shadowIntensity,
                    _shadowAlpha);
        }

        private void ApplySortingOrder(Vector2Int slotIndex)
        {
            var baseOrder = (slotIndex.x + slotIndex.y * _config.SlotsSize.x) * _baseSortingLayer;

            for (var i = 0; i < _spriteLayerRenderers.Length; i++)
                _spriteLayerRenderers[i].sortingOrder = baseOrder + i + 1;
        }
    }
}

