using System;
using BalloonParty.Shared;
using UnityEngine;
using UnityEngine.UI;

#endregion

namespace BalloonParty.UI.Score
{
    public class ScoreNotice : MonoBehaviour, IPoolable
    {
        [SerializeField] private Graphic[] _graphicsToSetColor;
        [SerializeField] private Animator _animator;
        [SerializeField] private Text _label;
        [SerializeField] private Text _shadow;
        [SerializeField] private float _maxScale = 2f;
        [SerializeField] private float _maxScaleScore = 100f;

        private Action<ScoreNotice> _returnToPool;
        private bool _animationStarted;
        private bool _showing;

        public void OnSpawned()
        {
            _showing = false;
            _animationStarted = false;
        }

        public void OnDespawned() { }

        public void Initialize(Action<ScoreNotice> returnToPool)
        {
            _returnToPool = returnToPool;
            InvokeRepeating(nameof(CheckAvailability), 0f, 0.15f);
        }

        public void Show(int score, Color color)
        {
            _showing = true;
            _animationStarted = false;

            foreach (var g in _graphicsToSetColor)
            {
                g.color = color;
            }

            _animator.SetTrigger("Score");
            _label.text = _shadow.text = score.ToString("N0");

            transform.localScale = Vector3.one;
            transform.localScale = Vector3.Lerp(Vector3.one, Vector3.one * _maxScale, score / _maxScaleScore);
        }

        private void CheckAvailability()
        {
            if (!_showing)
            {
                return;
            }

            var isAvailable = _animator.GetCurrentAnimatorStateInfo(0).IsTag("Available");

            if (!_animationStarted)
            {
                if (!isAvailable)
                {
                    _animationStarted = true;
                }

                return;
            }

            if (isAvailable)
            {
                _showing = false;
                _returnToPool?.Invoke(this);
            }
        }
    }
}

using System;
using BalloonParty.Projectile.Model;
using BalloonParty.Shared.Messages;
using MessagePipe;
using UniRx;
using UnityEngine;
using VContainer;

namespace BalloonParty.UI.Shields
{
    [RequireComponent(typeof(Animator))]
    public class ShieldCounterAnimation : MonoBehaviour
    {
        [Inject] private ShieldCounterLabel[] _labels;

        [Inject] private ISubscriber<ProjectileLoadedMessage> _loadedSubscriber;
        [Inject] private ISubscriber<BalanceBalloonsMessage> _balanceSubscriber;

        private readonly CompositeDisposable _disposable = new();
        private Animator _animator;
        private int _lastShieldValue;
        private IDisposable _shieldSubscription;

        private void Awake()
        {
            _animator = GetComponent<Animator>();
            _animator.SetTrigger("Waiting");
        }

        [Inject]
        private void Initialize()
        {
            _loadedSubscriber.Subscribe(OnProjectileLoaded).AddTo(_disposable);
            _balanceSubscriber.Subscribe(_ => OnBalancing()).AddTo(_disposable);
        }

        private void OnDestroy()
        {
            _disposable.Dispose();
            _shieldSubscription?.Dispose();
        }

        private void BindProjectile(ProjectileModel model)
        {
            _shieldSubscription?.Dispose();
            _lastShieldValue = model.ShieldsRemaining.Value;

            _shieldSubscription = model.ShieldsRemaining
                .Skip(1)
                .Subscribe(value =>
                {
                    _animator.SetTrigger(value > _lastShieldValue ? "Gain" : "Lost");
                    _lastShieldValue = value;
                });
        }

        private void OnProjectileLoaded(ProjectileLoadedMessage msg)
        {
            BindProjectile(msg.Model);
            foreach (var label in _labels) label.Bind(msg.Model.ShieldsRemaining);
            _animator.ResetTrigger("Waiting");
            _animator.ResetTrigger("Lost");
            _animator.SetTrigger("Ready");
        }

        private void OnBalancing()
        {
            _animator.SetTrigger("Waiting");
            _shieldSubscription?.Dispose();
            foreach (var label in _labels) label.Unbind();
        }
    }
}

using System;
using BalloonParty.Projectile.Model;
using BalloonParty.Shared.Messages;
using MessagePipe;
using UniRx;
using UnityEngine;
using VContainer;

namespace BalloonParty.UI.Shields
{
    [RequireComponent(typeof(Animator))]
    public class ShieldCounterAnimation : MonoBehaviour
    {
        [Inject] private ShieldCounterLabel[] _labels;

        [Inject] private ISubscriber<ProjectileLoadedMessage> _loadedSubscriber;
        [Inject] private ISubscriber<ProjectileDestroyedMessage> _destroyedSubscriber;

        private readonly CompositeDisposable _disposable = new();
        private Animator _animator;
        private int _lastShieldValue;
        private bool _projectileAlive;
        private IDisposable _shieldSubscription;

        private void Awake()
        {
            _animator = GetComponent<Animator>();
            _animator.SetTrigger("Waiting");
        }

        [Inject]
        private void Initialize()
        {
            _loadedSubscriber.Subscribe(OnProjectileLoaded).AddTo(_disposable);
            _destroyedSubscriber.Subscribe(_ => OnProjectileDestroyed()).AddTo(_disposable);
        }

        private void OnDestroy()
        {
            _disposable.Dispose();
            _shieldSubscription?.Dispose();
        }

        private void BindProjectile(ProjectileModel model)
        {
            _shieldSubscription?.Dispose();
            _lastShieldValue = model.ShieldsRemaining.Value;

            _shieldSubscription = model.ShieldsRemaining
                .Skip(1)
                .Subscribe(value =>
                {
                    _animator.SetTrigger(value > _lastShieldValue ? "Gain" : "Lost");
                    _lastShieldValue = value;
                });
        }

        private void OnProjectileLoaded(ProjectileLoadedMessage msg)
        {
            _projectileAlive = true;
            BindProjectile(msg.Model);
            foreach (var label in _labels) label.Bind(msg.Model.ShieldsRemaining);
            _animator.ResetTrigger("Waiting");
            _animator.ResetTrigger("Lost");
            _animator.SetTrigger("Ready");
        }

        private void OnProjectileDestroyed()
        {
            _projectileAlive = false;
            _animator.SetTrigger("Waiting");
            _shieldSubscription?.Dispose();
            foreach (var label in _labels) label.Unbind();
        }
    }
}

#region

using System;
using System.Collections.Generic;
using BalloonParty.Balloon.Model;
using BalloonParty.Configuration;
using UniRx;
using UnityEngine;

#endregion

namespace BalloonParty.Balloon.PowerUps
{
    public class BalloonPowerUpDisplay : MonoBehaviour
    {
        [SerializeField] private List<PowerUpVisual> _visuals;
        [SerializeField] private SpriteRenderer[] _spritesToSetColor;
        [SerializeField] private Renderer[] _sortingRenderers;
        [SerializeField, Range(0f, 1f)] private float _spritesAlpha;

        private readonly CompositeDisposable _disposables = new();

        private PowerUpVisual _activeVisual;

        public void Bind(IBalloonModel model, IGameConfiguration config, int baseSortingOffset)
        {
            Unbind();

            model.PowerUp
                .Subscribe(type => OnPowerUpChanged(type, model, config))
                .AddTo(_disposables);

            model.SlotIndex
                .Subscribe(slot => ApplySortingOrder(slot, config, baseSortingOffset))
                .AddTo(_disposables);
        }

        public void Unbind()
        {
            _disposables.Clear();
            _activeVisual = null;

            foreach (var visual in _visuals)
            {
                visual.Root.SetActive(false);
            }
        }

        private void OnPowerUpChanged(BalloonPowerUp type, IBalloonModel model, IGameConfiguration config)
        {
            _activeVisual = null;

            foreach (var visual in _visuals)
            {
                var isMatch = visual.Type == type;
                visual.Root.SetActive(isMatch);

                if (isMatch)
                {
                    _activeVisual = visual;
                }
            }

            if (_activeVisual == null || type == BalloonPowerUp.None)
            {
                return;
            }

            var balloonColor = config.BalloonColor(model.Color.Value);
            foreach (var sr in _spritesToSetColor)
            {
                sr.color = new Color(balloonColor.r, balloonColor.g, balloonColor.b, _spritesAlpha);
            }
        }

        private void ApplySortingOrder(Vector2Int slotIndex, IGameConfiguration config, int baseSortingOffset)
        {
            if (_sortingRenderers == null || _sortingRenderers.Length == 0)
            {
                return;
            }

            var maxRow = config.SlotsSize.y - 1;
            var baseOrder = (slotIndex.x + ((maxRow - slotIndex.y) * config.SlotsSize.x)) * baseSortingOffset;
            var startOrder = baseOrder + baseSortingOffset;

            for (var i = 0; i < _sortingRenderers.Length; i++)
            {
                _sortingRenderers[i].sortingOrder = startOrder + i + 1;
            }
        }

        [Serializable]
        public class PowerUpVisual
        {
            public BalloonPowerUp Type;
            public GameObject Root;
        }
    }
}

using UnityEngine;

namespace BalloonParty.Balloon.PowerUps
{
    public class LaserPowerUpRotation : MonoBehaviour
    {
        [SerializeField] private float _rotationSpeed;

        private float _angle;

        private void Update()
        {
            _angle += _rotationSpeed * Time.deltaTime;
            transform.rotation = Quaternion.AngleAxis(_angle, Vector3.forward);
        }

